"use strict";parserFactory.register("global.novelpia.com",()=>new GlobalNovelpiaParser);class GlobalNovelpiaParser extends Parser{constructor(){super(),this.minimumThrottle=3e3}async getChapterUrls(t){const e=t.baseURI.match(/\/novel\/(\d+)/)?.[0].slice(7),r=`https://api-global.novelpia.com/v1/novel/episode/cursor-list?novel_no=${e}&rows=9999&sort=ASC`;try{return(await HttpClient.fetchJson(r)).json.result.list.map(t=>({sourceUrl:`https://global.novelpia.com/viewer/${t.episode_no}`,title:t.epi_num+" - "+t.epi_title}))}catch(t){ErrorLog.showErrorMessage(t)}}findContent(t){return Parser.findConstrutedContent(t)}extractTitleImpl(t){return t.querySelector(".nv-tit")}extractAuthor(t){let e=t.querySelector(".info-author");return e?.textContent??super.extractAuthor(t)}extractLanguage(t){return t.querySelector("html").getAttribute("lang")}extractSubject(t){return[...t.querySelectorAll(".nv-tag")].map(t=>t.textContent.trim()).join(", ")}extractDescription(t){return t.querySelector(".synopsis-text").textContent.trim()}findChapterTitle(t){return t.querySelector(".in-ch-txt")}findCoverImageUrl(t){return util.getFirstImgSrc(t,".cover-box")}async fetchChapter(t){let e=(await HttpClient.fetchHtml(t)).responseXML,r=e.querySelector("span.in-chapter-number")?.textContent,n=e.querySelector("span.in-chapter-title")?.textContent,o=`https://api-global.novelpia.com/v1/novel/episode/content?_t=${this.findChapterContentToken(e)}`,l=(await HttpClient.fetchJson(o)).json;return this.jsonToHtml(t,l.result.data,r+" - "+n)}findChapterContentToken(t){let e=new RegExp('eyJhb[^"]*'),r=t.querySelector("script#__NUXT_DATA__")?.outerHTML,n=r?.match(e);return n}jsonToHtml(t,e,r){let n=Parser.makeEmptyDocForContent(t),o=n.dom.createElement("h1");o.textContent=r,n.content.appendChild(o);let l=Object.keys(e).filter(t=>t.startsWith("epi_content")).map(t=>e[t]),i=util.sanitize("<div>"+l.join("")+"</div>");return util.moveChildElements(i.body,n.content),n.dom}removeUnwantedElementsFromContentElement(t){util.removeChildElementsMatchingSelector(t,".next-epi-btn"),super.removeUnwantedElementsFromContentElement(t)}getInformationEpubItemChildNodes(t){return[...t.querySelectorAll(".nv-synopsis")]}cleanInformationNode(t){return util.removeChildElementsMatchingSelector(t,"button"),t}}